where c.del_flag = '0'

    and c.task_id = #{taskId}


    and c.user_id = #{userId}


    and COALESCE(NULLIF(u.user_name, ''), c.user_name) like concat('%', #{userName}, '%')


    and c.check_in_type = #{checkInType}


    and date_format(c.check_in_time,'%y%m%d') >= date_format(#{params.beginTime},'%y%m%d')


    and date_format(c.check_in_time,'%y%m%d') <= date_format(#{params.endTime},'%y%m%d')


    and c.company_id = #{companyId}

order by c.check_in_time desc

